vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vUv = (vUv-vUvOriginal)*(1+abs(lum(GetBlur2(vUv)-GetBlur1(vUv)))*-16) + vUvOriginal;
int f2 = uFrame%2;
vUv.x += (f2-.5)*uTexSize.z;
ret = texture(sampler_fw_main, vUv);

ret -= 0.006 * f2;
//ret -= clamp01(vUv.y-.5)*0.05;



  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

uv6 = (vUv-0.5)* 1.5*(1+-1*pow(vUv.y-.5,1.5)) + .5;
vUv = mix(vUv,uv6,0);
uv1 = (vUv-center);

ret1 = pow(clamp01(1-1*vUv.y),2)*vec3(0,q20,q21);
int anz = 3;
int n = 0;
dz=0; dz1=0;
while (n < anz) {
  float dist = (1-fract(1.0/anz*n))*.9;
  float inten =  clamp01(1-dist*.75);
  uv3 = q25*anz*(uv1+vec2(0,q2*.25-0.1))*dist + center;
  float mask = clamp01(4-8*max(abs(uv3.x-.5),abs(uv3.y-.5)));
  dz0.x = lum(GP(uv3+hor))- lum(GP (uv3-hor))*q26;
  dz0.y = lum(GP(uv3+ver))- lum(GP (uv3-ver))*q26;
  dz += inten*mask*dz0;
  dz0.x = (lum(GP(uv3+hor))- lum(GP (uv3-hor)));
  dz0.y = (lum(GP(uv3+ver))- lum(GP (uv3-ver)));
  dz1 += inten*mask*dz0;
  neu = max(GP(uv3+dz*.1),GetBlur3(uv3)*.70*rand_preset.y);
  ret1 = max(ret1,neu*mask*inten);
n++;}

uv1= multiply((vUv-.5)*uAspect.xy,rot45);
dz = multiply(dz*uAspect.xy ,rot45);
uv6 = sin(10*uv1+dz*16 + vec2(uTime*.2,0));
mus = 1/length(uv6) * (1+4*length(dz1)*sqrt(audioHighSmooth)*(1+4*GetBlur2(fract((0.6-vUv)*0.25+.5))));

ret = sqrt(ret1)*(-.1+rand_preset.z*.3+mus*.5);
ret = 1-exp(-ret*(2-1.99*vRadius*rand_preset.y));
//ret = GetPixel(vUv);

  fragColor = ret;
}
